import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import ComplaintModal from '../components/ComplaintModal';
import moment from 'moment';
import toast from 'react-hot-toast';
import { FaHeart, FaRegHeart, FaComment, FaShare, FaFlag } from 'react-icons/fa';

export default function VideoPlayer() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [video, setVideo] = useState(null);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState('');
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [isLiked, setIsLiked] = useState(false);
    const [likesCount, setLikesCount] = useState(0);
    const [showComplaintModal, setShowComplaintModal] = useState(false);

    useEffect(() => {
        fetchVideo();
        fetchComments();
    }, [id]);

    const fetchVideo = async () => {
        try {
            const response = await axios.get(`/videos/${id}/`);
            setVideo(response.data);
            setIsLiked(response.data.is_liked || false);
            setLikesCount(response.data.like_count || 0);
        } catch (error) {
            console.error('Error fetching video:', error);
            toast.error('Видео не найдено');
            navigate('/');
        } finally {
            setLoading(false);
        }
    };

    const fetchComments = async () => {
        try {
            const response = await axios.get(`/videos/${id}/comments/`);
            setComments(response.data);
        } catch (error) {
            console.error('Error fetching comments:', error);
            setComments([]);
        }
    };

    const handleLike = async () => {
        if (!user) {
            toast.error('Войдите чтобы поставить лайк');
            return;
        }
        try {
            const response = await axios.post(`/videos/${id}/like/`);
            setIsLiked(response.data.status === 'liked');
            setLikesCount(response.data.count);
        } catch (error) {
            console.error('Error liking video:', error);
            toast.error('Ошибка');
        }
    };

    const handleComment = async (e) => {
        e.preventDefault();

        if (!user) {
            toast.error('Войдите чтобы оставить комментарий');
            return;
        }

        if (!newComment.trim()) {
            toast.error('Напишите комментарий');
            return;
        }

        setSubmitting(true);
        try {
            const token = localStorage.getItem('access_token');
            await axios.post(
                `/videos/${id}/comments/`,
                { text: newComment },
                { headers: { 'Authorization': `Bearer ${token}` } }
            );
            setNewComment('');
            fetchComments();
            toast.success('Комментарий добавлен!');
        } catch (error) {
            console.error('Error adding comment:', error);
            toast.error('Ошибка добавления комментария');
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteComment = async (commentId) => {
        if (!user) return;

        if (!window.confirm('Удалить комментарий?')) return;

        try {
            const token = localStorage.getItem('access_token');
            await axios.delete(`/videos/${id}/comments/`, {
                headers: { 'Authorization': `Bearer ${token}` },
                data: { comment_id: commentId }
            });
            fetchComments();
            toast.success('Комментарий удален');
        } catch (error) {
            console.error('Error deleting comment:', error);
            toast.error('Ошибка удаления');
        }
    };

    const handleComplaint = () => {
        if (!user) {
            toast.error('Войдите чтобы пожаловаться');
            return;
        }
        setShowComplaintModal(true);
    };

    if (loading) {
        return <div className="flex justify-center items-center h-screen text-white">Загрузка...</div>;
    }

    if (!video) {
        return <div className="flex justify-center items-center h-screen text-white">Видео не найдено</div>;
    }

    const isAdmin = user?.is_staff || user?.username === 'admin';

    return (
        <div className="pt-16 bg-black min-h-screen">
            {showComplaintModal && (
                <ComplaintModal videoId={id} onClose={() => setShowComplaintModal(false)} />
            )}

            <div className="container mx-auto px-4 py-8">
                <div className="flex flex-col lg:flex-row gap-8">
                    <div className="lg:w-3/4">
                        <div className="bg-black rounded-xl overflow-hidden">
                            <video
                                controls
                                autoPlay
                                className="w-full"
                                style={{ maxHeight: '70vh' }}
                                src={video.video_file}
                            />
                        </div>

                        <div className="mt-6">
                            <h1 className="text-2xl font-bold text-white">{video.title}</h1>
                            <div className="flex items-center justify-between mt-4 pb-4 border-b border-gray-800 flex-wrap gap-4">
                                <div className="flex items-center space-x-4">
                                    <div className="flex items-center space-x-3">
                                        <div className="w-12 h-12 bg-purple-600 rounded-full flex items-center justify-center cursor-pointer">
                                            <span className="text-white font-bold text-lg">
                                                {video.author?.username?.[0]?.toUpperCase()}
                                            </span>
                                        </div>
                                        <div>
                                            <p className="font-semibold text-white hover:text-purple-400 cursor-pointer">
                                                {video.author?.username}
                                            </p>
                                            <p className="text-sm text-gray-400">{video.author?.subscriber_count} подписчиков</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center space-x-3">
                                    <button
                                        onClick={handleLike}
                                        className={`flex items-center space-x-2 px-6 py-2 rounded-full transition ${
                                            isLiked ? 'bg-red-600 text-white' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                                        }`}
                                    >
                                        {isLiked ? <FaHeart /> : <FaRegHeart />}
                                        <span>{likesCount}</span>
                                    </button>
                                    <button
                                        onClick={handleComplaint}
                                        className="flex items-center space-x-2 px-4 py-2 bg-gray-800 rounded-full hover:bg-gray-700 transition text-gray-300"
                                        title="Пожаловаться"
                                    >
                                        <FaFlag />
                                        <span>Жалоба</span>
                                    </button>
                                </div>
                            </div>

                            <div className="mt-4 p-4 bg-gray-900 rounded-xl">
                                <p className="text-gray-300">{video.description || 'Нет описания'}</p>
                                <p className="text-sm text-gray-500 mt-2">{video.views} просмотров</p>
                            </div>

                            {/* Комментарии */}
                            <div className="mt-8">
                                <h3 className="text-xl font-bold text-white mb-4">
                                    💬 Комментарии ({comments.length})
                                </h3>

                                <form onSubmit={handleComment} className="mb-6">
                                    <div className="flex space-x-3">
                                        <div className="flex-1">
                                            <textarea
                                                value={newComment}
                                                onChange={(e) => setNewComment(e.target.value)}
                                                placeholder={user ? "Напишите комментарий..." : "Войдите чтобы оставить комментарий"}
                                                disabled={!user || submitting}
                                                rows="3"
                                                className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-purple-500 disabled:opacity-50"
                                            />
                                        </div>
                                    </div>
                                    {user && (
                                        <div className="mt-2 text-right">
                                            <button
                                                type="submit"
                                                disabled={submitting}
                                                className="px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition font-semibold disabled:opacity-50"
                                            >
                                                {submitting ? 'Отправка...' : 'Отправить'}
                                            </button>
                                        </div>
                                    )}
                                </form>

                                <div className="space-y-4">
                                    {comments.length === 0 ? (
                                        <div className="text-center text-gray-500 py-8 bg-gray-900 rounded-lg">
                                            <p>Нет комментариев. Будьте первым! 💬</p>
                                        </div>
                                    ) : (
                                        comments.map(comment => {
                                            const canDelete = user && (comment.user.id === user.id || isAdmin);
                                            return (
                                                <div key={comment.id} className="p-4 bg-gray-900 rounded-lg hover:bg-gray-800 transition">
                                                    <div className="flex items-start justify-between">
                                                        <div className="flex items-start space-x-3 flex-1">
                                                            <div className="w-8 h-8 bg-gray-700 rounded-full flex items-center justify-center flex-shrink-0">
                                                                <span className="text-white text-sm">
                                                                    {comment.user?.username?.[0]?.toUpperCase()}
                                                                </span>
                                                            </div>
                                                            <div className="flex-1">
                                                                <div className="flex items-center space-x-2 mb-1">
                                                                    <span className="font-semibold text-purple-400">
                                                                        {comment.user?.username}
                                                                        {comment.user?.is_staff && (
                                                                            <span className="ml-1 text-xs bg-red-600 px-1 rounded">Admin</span>
                                                                        )}
                                                                    </span>
                                                                    <span className="text-gray-500 text-xs">
                                                                        {moment(comment.created_at).fromNow()}
                                                                    </span>
                                                                </div>
                                                                <p className="text-gray-300">{comment.text}</p>
                                                            </div>
                                                        </div>
                                                        {canDelete && (
                                                            <button
                                                                onClick={() => handleDeleteComment(comment.id)}
                                                                className="text-gray-500 hover:text-red-500 transition text-sm ml-2"
                                                                title="Удалить комментарий"
                                                            >
                                                                🗑️
                                                            </button>
                                                        )}
                                                    </div>
                                                </div>
                                            );
                                        })
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="lg:w-1/4">
                        <h3 className="text-xl font-bold text-white mb-4">🎬 Рекомендации</h3>
                        <div className="text-center text-gray-500 py-8 bg-gray-900 rounded-lg">
                            <p>Скоро здесь будут рекомендации</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
